import application.ApplicationExecutor
import ui.CliManager

fun main(args: Array<String>) {
    val cliManager = CliManager()
    val app = ApplicationExecutor(cliManager, args.getOrNull(0) ?: "")
    if (Math.random() > 0.9) idk()
    app.run()

    val gen = Math.random()
    mostValuableFunc()
}

